                <div className="flex justify-end space-x-3 mt-8 pt-4 border-t border-gray-100">
                  <button
                    type="button"
                    onClick={() => setEditMode(false)}
                    className="px-5 py-2 bg-gray-500 text-white rounded-lg hover:bg-gray-600 transition"
                  >
                    취소
                  </button>
                  <button
                    type="submit"
                    className="px-5 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition"
                  >
                    저장
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* 음성 인식 결과 모달 */}
      {showVoiceResultModal && voiceAnalysis && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-xl p-6 max-w-md w-full mx-4">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xl font-bold text-gray-800">음성 인식 분석 결과</h3>
              <button
                onClick={() => {
                  setShowVoiceResultModal(false);
                  setVoiceAnalysis({ time: '', summary: '', category: '' });
                  setTranscript('');
                }}
                className="text-gray-400 hover:text-gray-600"
              >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              </button>
            </div>

            <div className="space-y-4">
              <div>
                <p className="text-sm text-gray-600 mb-1">시간</p>
                <p className="font-medium text-gray-800">{voiceAnalysis.time}</p>
              </div>

              <div>
                <p className="text-sm text-gray-600 mb-1">일정 요약</p>
                <p className="font-medium text-gray-800">{voiceAnalysis.summary}</p>
              </div>

              <div>
                <p className="text-sm text-gray-600 mb-1">카테고리</p>
                <p className="font-medium text-gray-800">{voiceAnalysis.category}</p>
              </div>
            </div>

            <div className="mt-6 flex justify-end space-x-3">
              <button
                onClick={() => {
                  setShowVoiceResultModal(false);
                  setVoiceAnalysis({ time: '', summary: '', category: '' });
                  setTranscript('');
                }}
                className="px-4 py-2 bg-gray-100 text-gray-700 rounded-md hover:bg-gray-200 transition"
              >
                닫기
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// Main App component with Router and Auth context
function App() {
  const [authView, setAuthView] = useState('login'); // 'login', 'register', 'forgot-password'

  const handleLoginSuccess = (userData) => {
    console.log('로그인 성공:', userData);
    // 로그인 성공 후 메인 페이지로 리다이렉트
    window.location.href = '/';
  };

  const handleRegisterSuccess = (view = 'login') => {
    setAuthView(view);
  };

  return (
    <AuthProvider>
      <Router>
        <Routes>
          <Route path="/login" element={
            authView === 'login' ? (
              <Login 
                onLogin={handleLoginSuccess} 
                onForgotPassword={() => setAuthView('forgot-password')}
                onRegister={() => setAuthView('register')}
              />
            ) : authView === 'register' ? (
              <Register onRegisterSuccess={handleRegisterSuccess} />
            ) : (
              <ForgotPassword 
                onSuccess={() => setAuthView('login')}
                onBackToLogin={() => setAuthView('login')}
              />
            )
          } />
          <Route path="/register" element={<Register onRegisterSuccess={handleRegisterSuccess} />} />
          <Route path="/reset-password" element={<ResetPassword onSuccess={() => window.location.href = '/login'} />} />
          <Route path="/" element={
            <PrivateRoute>
              <CalendarApp />
            </PrivateRoute>
          } />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Router>
    </AuthProvider>
  );
}

export default App;
